#include <bits/stdc++.h>using namespace std;#define int long longint ans[1000009];int vis[1000009];int sum;int num[1000009];int n;bool flag=0;void dfs(int x){    if(flag==1)    {        return ;    }    if(x==n+1)    {         for(int i=n;i>=3;--i)        {            if(ans[i]==ans[i-1]+ans[i-2])            {                return ;            }        }        sum++;        if(sum>n)        {            sum=0;            flag=1;            return ;        }        for(int i=1;i<=n;++i)        {            cout<<ans[i]<<' ';        }        cout<<endl;        return ;    }    for(int i=1;i<=n;++i)    {        if(vis[i]==0)        {            if(x>=3)            {                if(ans[x-1]+ans[x-2]==i)                {                    return ;                }            }            vis[i]=1;            ans[x]=i;            dfs(x+1);            vis[i]=0;        }    }    return ;}signed main(){    int t;    cin>>t;    while(t--)    {        flag=0;        memset(vis,0,sizeof(vis));        cin>>n;        dfs(1);    }    return 0;}